#include <stdio.h>
int main() {
    int N, Q, K;
    scanf("%d %d %d", &N, &Q, &K);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    char S[Q + 1];
    scanf("%s", S);
    for (int i = 0; i < Q; i++) {
        if (S[i] == '!') {
            int temp = A[N - 1];
            for (int j = N - 1; j > 0; j--) {
                A[j] = A[j - 1];
            }
            A[0] = temp;
        } else {
            int maxLen = 0;
            for (int j = 0; j < N; j++) {
                int len = 0;
                for (int k = j; k < N && k < j + K; k++) {
                    if (A[k] == 1) {
                        len++;
                    } else {
                        break;
                    }
                }
                maxLen = (len > maxLen) ? len : maxLen;
            }
            printf("%d\n", maxLen);
        }
    }
    return 0;
}

