public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int Q = sc.nextInt();
        int K = sc.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.nextInt();
        }
        String S = sc.next();
        for (int i = 0; i < Q; i++) {
            if (S.charAt(i) == '!') {
                int temp = A[N - 1];
                for (int j = N - 1; j > 0; j--) {
                    A[j] = A[j - 1];
                }
                A[0] = temp;
            } else {
                int maxLen = 0;
                for (int j = 0; j < N; j++) {
                    int len = 0;
                    for (int k = j; k < N && k < j + K; k++) {
                        if (A[k] == 1) {
                            len++;
